<template>
  <div v-if="this.$parent.takeSelfie" class="take-photo">
    <div class="take-photo__camera">
      <p class="paragraph--dark take-photo__header">Centra tu cara en la siguiente retícula</p>
      <div class="camera-button">
        <a type="button" class="button--small is-rounded" :class="{ 'is-primary' : !isCameraOpen, 'is-danger' : isCameraOpen}" @click="toggleCamera">
          <span v-if="!isCameraOpen">Abrir cámara</span>
          <span v-else>Cerrar cámara</span>
        </a>
      </div>
      <button @click="this.$parent.takeSelfie = false; stopCameraStream ();" class="close">X</button>
      <div class="camera-box">
        <div v-show="!isPhotoTaken" class="video--container__selfie">
          <video class="camera-video" ref="camera" :width="450" :height="337.5" autoplay playsinline></video>
        </div>
        <canvas class="canvas-photo" v-show="isPhotoTaken" id="photoTaken" ref="canvas" :width="420" :height="280"></canvas>
      </div>
      <p v-if="!isPhotoTaken" class="paragraph--light">Ten en cuenta que el de la foto debes ser únicamente tú y coincidir
        con la persona en el documento de identificación.</p>
      <div v-else class="photo-footer">
        <p class="paragraph--dark photo-footer__header">Foto realizada. Ahora revísala</p>
        <p class="paragraph--light photo-footer__desc">Ten en cuenta que el de la foto debes ser únicamente tú <br> y coincidir
        con la persona en el documento de identificación.
        </p>
        <button @click="isPhotoTaken = false" class="button--gray photo-footer__button">Volver a intentarlo</button>
        <button @click="this.$parent.takeSelfie = false; stopCameraStream ();" class="photo-footer__button">Confirmar</button>
      </div>
      <div v-if="!isPhotoTaken" class="camera-shoot">
        <camera-icon type="button" class="button--small" @click="takePhoto"></camera-icon>
      </div>
    </div>
  </div>
</template>

<script>
import cameraIcon from '../../icons/signup/cameraIcon'

export default {
  name: 'TakePhoto',
  data () {
    return {
      isCameraOpen: false,
      isPhotoTaken: false
    }
  },
  methods: {
    createCameraElement () {
      const constraints = (window.constraints = {
        audio: false,
        video: true
      })

      navigator.mediaDevices
        .getUserMedia(constraints)
        .then(stream => {
          this.$refs.camera.srcObject = stream
        })
        .catch(error => {
          alert(error, "May the browser didn't support or there is some errors.")
        })
    },
    stopCameraStream () {
      const tracks = this.$refs.camera.srcObject.getTracks()

      tracks.forEach(track => {
        track.stop()
      })
      console.log('CameraClosed')
    },
    toggleCamera () {
      if (this.isCameraOpen) {
        this.isCameraOpen = false
        this.isPhotoTaken = false
        this.stopCameraStream()
      } else {
        this.isCameraOpen = true
        this.createCameraElement()
      }
    },
    takePhoto () {
      this.isPhotoTaken = !this.isPhotoTaken

      const context = this.$refs.canvas.getContext('2d')
      context.drawImage(this.$refs.camera, 180, 90, 300, 250, 50, 20, 350, 250)

      const photo = document.getElementById('photoTaken').toDataURL()
      console.log(photo)
    },
    savePhoto () {
    }
  },
  components: {
    cameraIcon
  }
}

</script>
